+package crdt
+
+import "testing"
+
+// TestORSet_MergeUnionsSharedTags ensures a shared element retains the union
+// of both replicas' tags after a bidirectional merge.
+func TestORSet_MergeUnionsSharedTags(t *testing.T) {
+	a := NewORSet("a")
+	b := NewORSet("b")
+
+	a.Add("x")
+	b.Add("x")
+
+	a.Merge(b)
+	b.Merge(a)
+
+	if !a.Contains("x") || !b.Contains("x") {
+		t.Fatal("both replicas must contain x after merge")
+	}
+	if got := len(a.entries["x"]); got != 2 {
+		t.Fatalf("replica a: expected union of 2 tags, got %d", got)
+	}
+	if got := len(b.entries["x"]); got != 2 {
+		t.Fatalf("replica b: expected union of 2 tags, got %d", got)
+	}
+}

